arguments.newString:
    #[cfg(windows)]
    {
        // Windows `fs::rename` refuses to overwrite an existing destination, so a
        // naive implementation must remove the destination first — which loses the
        // durable state if the process crashes between the delete and the rename.
        // Instead, move the existing file aside to a backup, promote the temp file,
        // and only then delete the backup. If promotion fails, the backup is
        // restored so the previous durable state is never lost.
        if path.exists() {
            let backup_path = parent.join(format!(
                ".{}.bak-{}",
                path.file_name()
                    .and_then(|name| name.to_str())
                    .unwrap_or("session"),
                uuid::Uuid::new_v4()
            ));
            fs::rename(path, &backup_path).map_err(|source| SessionError::Io {
                path: path.to_path_buf(),
                source,
            })?;
            match fs::rename(&tmp_path, path) {
                Ok(()) => {
                    // Replacement succeeded; the old state is now redundant.
                    let _ = fs::remove_file(&backup_path);
                },
                Err(source) => {
                    // Restore the previous durable state before surfacing the error.
                    let _ = fs::rename(&backup_path, path);
                    let _ = fs::remove_file(&tmp_path);
                    return Err(SessionError::Io {
                        path: path.to_path_buf(),
                        source,
                    });
                },
            }
        } else {
            fs::rename(&tmp_path, path).map_err(|source| SessionError::Io {
                path: path.to_path_buf(),
                source,
            })?;
        }
    }

    #[cfg(not(windows))]
    fs::rename(&tmp_path, path).map_err(|source| SessionError::Io {
        path: path.to_path_buf(),
        source,
    })?;

    if let Ok(parent_dir) = fs::File::open(parent) {
        let _ = parent_dir.sync_all();
    }

    Ok(())
}

