    let snapshot = self.workflow_snapshot(workspace_session_id, resolver)?;
    let live_states = snapshot
        .resolutions
        .iter()
        .map(|item| (item.node_id.clone(), item.live_ticket_state.clone()))
        .collect::<BTreeMap<_, _>>();
